import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    if not unvisited_customers:
        return None

    # Calculate the common backbone idea
    distances = np.linalg.norm(unvisited_customers - cur_truck_pos, axis=1)
    potential_impact = np.zeros(len(unvisited_customers))

    for i, customer in enumerate(unvisited_customers):
        for truck_pos in all_truck_pos:
            if np.array_equal(truck_pos, cur_truck_pos):
                continue
            alternative_distance = np.linalg.norm(truck_pos - customer)
            if alternative_distance < distances[i]:
                potential_impact[i] += distances[i] - alternative_distance

    # Description: {Incorporate waiting and speed into dynamic decision-making for next node selection to optimize fleet performance.}
    speed_factor = 2.0
    best_node = None
    min_effective_distance = float('inf')

    for i, impact in enumerate(potential_impact):
        effective_distance = distances[i] / speed_factor + impact
        if effective_distance < min_effective_distance:
            min_effective_distance = effective_distance
            best_node = i

    return best_node
